def seed_words(cur):
    """Вставляет HSK1_WORDS (150+ слов). Возвращает {hanzi: word_id}."""
    print("\n📖 Вставляю слова HSK-1...")
    word_ids = {}
    for hanzi, transcription, translation, audio_url, pos, example_s, example_t in HSK1_WORDS:
        cur.execute(
            """INSERT INTO words
               (hanzi, transcription, translation, audio_url, part_of_speech,
                example_sentence, example_translation)
               VALUES (%s, %s, %s, %s, %s, %s, %s)
               RETURNING id""",
            (hanzi, transcription, translation, audio_url, pos, example_s, example_t),
        )
        word_ids[hanzi] = cur.fetchone()[0]
    print(f"   ✅ Вставлено слов: {len(HSK1_WORDS)}")
    return word_ids


def seed_word_lesson_assignments(cur, word_ids, lesson_ids):
    """Привязывает слова к урокам по WORD_LESSON_ASSIGNMENTS (lesson_word_association)."""
    print("\n🔗 Привязываю слова к урокам (lesson_word_association)...")
    linked = 0
    skipped_lessons = 0
    skipped_words = 0
    for lesson_name, hanzi_list in WORD_LESSON_ASSIGNMENTS.items():
        lesson_id = lesson_ids.get(lesson_name)
        if lesson_id is None:
            print(f"   ~ Урок «{lesson_name}» не найден среди новых уроков, пропускаю привязку.")
            skipped_lessons += 1
            continue
        for hanzi in hanzi_list:
            word_id = word_ids.get(hanzi)
            if word_id is None:
                print(f"   ~ Слово «{hanzi}» не найдено, пропускаю.")
                skipped_words += 1
                continue
            cur.execute(
                """INSERT INTO lesson_word_association (lesson_id, word_id)
                   VALUES (%s, %s) ON CONFLICT DO NOTHING""",
                (lesson_id, word_id),
            )
            linked += 1
    print(f"   ✅ Привязано слов к урокам: {linked} (пропущено уроков: {skipped_lessons}, слов: {skipped_words})")

